package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    void testReadLine_NonNullNonEmptyLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        Reader reader = mock(Reader.class);
        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader) {
            @Override
            public String readLine() throws IOException {
                // call super.readLine() from BufferedReader (which calls reader.read())
                return super.readLine();
            }
        };

        ExtendedBufferedReader spyReader = spy(readerUnderTest);

        // Mock the underlying reader to return 'abc\n'
        doAnswer(invocation -> {
            char[] buf = (char[]) invocation.getArguments()[0];
            int off = (int) invocation.getArguments()[1];
            int len = (int) invocation.getArguments()[2];
            String s = "abc\n";
            int toCopy = Math.min(len, s.length());
            s.getChars(0, toCopy, buf, off);
            return toCopy;
        }).when(reader).read(any(char[].class), anyInt(), anyInt());

        String line = spyReader.readLine();

        assertEquals("abc", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(spyReader);
        assertEquals('c', lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(spyReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NonNullEmptyLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        Reader reader = mock(Reader.class);
        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader) {
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };

        ExtendedBufferedReader spyReader = spy(readerUnderTest);

        // Mock underlying reader to return only newline "\n"
        doAnswer(invocation -> {
            char[] buf = (char[]) invocation.getArguments()[0];
            int off = (int) invocation.getArguments()[1];
            int len = (int) invocation.getArguments()[2];
            String s = "\n";
            int toCopy = Math.min(len, s.length());
            s.getChars(0, toCopy, buf, off);
            return toCopy;
        }).when(reader).read(any(char[].class), anyInt(), anyInt());

        String line = spyReader.readLine();

        assertEquals("", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(spyReader);
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(spyReader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NullLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        Reader reader = mock(Reader.class);
        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader) {
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };

        ExtendedBufferedReader spyReader = spy(readerUnderTest);

        // Mock underlying reader to simulate end of stream
        doReturn(-1).when(reader).read(any(char[].class), anyInt(), anyInt());

        String line = spyReader.readLine();

        assertNull(line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(spyReader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(spyReader);
        assertEquals(0, lineCounter);
    }

    @Test
    void testReadLine_IOException() throws IOException {
        Reader reader = mock(Reader.class);
        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader) {
            @Override
            public String readLine() throws IOException {
                return super.readLine();
            }
        };

