        doThrow(new IOException("Test IO Exception")).when(reader).read(any(char[].class), anyInt(), anyInt());

        IOException thrown = assertThrows(IOException.class, spyReader::readLine);
        assertEquals("Test IO Exception", thrown.getMessage());
    }
}
